 * GLOBAL PROTOTYPES
 **********************/

static inline bool math_zero(float a)
{
    return (MATH_FABSF(a) < FLT_EPSILON);
}

static inline bool math_equal(float a, float b)
{
    return math_zero(a - b);
}

float math_fast_inv_sqrtf(float number);

/**********************
